#include <iostream>
#include <algorithm>
using namespace std;
int main()
{
    int n,a[200005],count=1;
    cin>>n;
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i];
    }
    a[n]=-1;
    sort(a,a+n);
    for(int i=0;i<=n-1;i++)
    {
        if(a[i]==a[i+1])
        {
            count++;
        }
        else
        {
            cout<<a[i]<<" "<<count<<endl;
            count=1;
        }
    }
    return 0;
}
